import{_ as e,o as a,c as n,a3 as o}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Tenant Settings — User Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant Settings — User Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/tenant-settings"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant Settings — User Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/tenant-settings"}]]},"headers":[],"relativePath":"user-guide/tenant-settings.md","filePath":"user-guide/tenant-settings.md","lastUpdated":1784733008000}'),r={name:"user-guide/tenant-settings.md"};function s(i,t,d,l,g,c){return a(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="tenant-settings-—-user-guide" tabindex="-1">Tenant Settings — User Guide <a class="header-anchor" href="#tenant-settings-—-user-guide" aria-label="Permalink to &quot;Tenant Settings — User Guide&quot;">​</a></h1><p>Workspace <strong>Settings</strong> lets each tenant customize identity and mail without affecting other workspaces or the Central Application.</p><h2 id="open-settings" tabindex="-1">Open Settings <a class="header-anchor" href="#open-settings" aria-label="Permalink to &quot;Open Settings&quot;">​</a></h2><p>In the Tenant Application sidebar, open <strong>Settings</strong>.</p><p>You need permission to view/update settings (workspace owners have this by default).</p><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>Workspace Name</strong></td><td>Display name for the workspace. Also used as the browser/app title unless you set Application Name.</td></tr><tr><td><strong>Application Name</strong></td><td>Optional title override. Leave blank to use Workspace Name.</td></tr><tr><td><strong>Company Name</strong></td><td>Used in emails and documents.</td></tr><tr><td><strong>Timezone / Locale / Currency</strong></td><td>Workspace defaults. Inherit from Central when not customized.</td></tr><tr><td><strong>Daily task reminder time</strong></td><td>Local workspace time for the once-per-day consolidated task email (default <code>09:00</code>). Assignees still get in-app alerts per due/overdue task.</td></tr><tr><td><strong>Default meeting provider</strong></td><td>Preselects None / Google Meet / Zoom on the Meetings schedule form (<code>meetings_default_provider</code>). Connecting providers is done under Meetings → Integrations.</td></tr></tbody></table><h2 id="branding" tabindex="-1">Branding <a class="header-anchor" href="#branding" aria-label="Permalink to &quot;Branding&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>Button color</strong></td><td>Primary buttons and accents for this workspace only.</td></tr><tr><td><strong>Support email</strong></td><td>Shown in tenant-facing emails when set.</td></tr><tr><td><strong>Logo / Favicon</strong></td><td>Upload immediately. If unset, the platform (Central) logo/favicon is used automatically.</td></tr></tbody></table><p>Hints under fields show when a value is still inheriting the Central default.</p><h2 id="mail" tabindex="-1">Mail <a class="header-anchor" href="#mail" aria-label="Permalink to &quot;Mail&quot;">​</a></h2><p>Choose <strong>Use system provider</strong> to inherit Central Application mail, or <strong>Use custom provider</strong> for workspace-specific SMTP / Postmark / Mailgun.</p><ul><li>Password and API token fields never show the stored secret; leave blank to keep the existing value.</li><li>With a custom Postmark/Mailgun provider, copy the workspace <strong>Webhook URL</strong>, set the signing secret, and select delivery events to process.</li><li>Use <strong>Send test</strong> to verify delivery (uses the form values, including unsaved changes when supported).</li><li>Delivery history is available under <strong>Email logs</strong> — open a message to view the full body and <strong>Resend</strong> when permitted.</li></ul><h2 id="what-you-cannot-change" tabindex="-1">What you cannot change <a class="header-anchor" href="#what-you-cannot-change" aria-label="Permalink to &quot;What you cannot change&quot;">​</a></h2><p>Platform registration, maintenance mode, password policy, and billing defaults stay under Central Settings.</p>',15)])])}const u=e(r,[["render",s]]);export{h as __pageData,u as default};
